#include <bits/stdc++.h>
using namespace std;

int t, n, P, Q;
int p[105], c[105];
int f[50005];

int main() {
    cin >> t;
    while (t--) {
        memset(f, 0, sizeof(f));
        cin >> n >> P >> Q;
        for (int i = 1; i <= n; i++) {
            cin >> p[i] >> c[i];
        }
        for (int i = 1; i <= n; i++) {
            for (int j = Q; j >= c[i]; j--) {
                f[j] = max(f[j], f[j - c[i]] + p[i]);
            }
        }
        bool flag = true;
        for (int i = 1; i <= Q; i++) {
            if (f[i] >= P) {
                cout << i << endl;
                flag = false;
                break;
            }
        }
        if (flag) {
            cout << -1 << endl;
        }
    }
    return 0;
}
